class Solution {
public:
    bool checkIfPangram(string &s) {
        set<char> alphabet(26, '0');
        for (char &c : s) {
            if (c >= 'a' && c <= 'z') {
                alphabet.insert(c);
            }
        }
        set<char> eng_alphabet(26, '0');
        for (char c = 'a'; c <= 'z'; c++) {
            eng_alphabet.insert(c);
        }
        return eng_alphabet == alphabet;
    }
};

